import{_ as r,c as e,o as l,a5 as t}from"./chunks/framework.BtqC3pLB.js";const _=JSON.parse('{"title":"日本 -> 青森 -> 青森","description":"","frontmatter":{},"headers":[],"relativePath":"日本/青森/index.md","filePath":"docs/日本/青森/index.md","lastUpdated":1766646134000}'),i={name:"日本/青森/index.md"};function n(o,a,s,d,h,c){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="青森" tabindex="-1">青森 <a class="header-anchor" href="#青森" aria-label="Permalink to “青森”">​</a></h1><h2 id="蘋果與祭典之鄉" tabindex="-1">蘋果與祭典之鄉 <a class="header-anchor" href="#蘋果與祭典之鄉" aria-label="Permalink to “蘋果與祭典之鄉”">​</a></h2><p>青森縣位於本州島的最北端，以其美味的蘋果、壯觀的睡魔祭以及豐富的自然景觀而聞名。從壯麗的奧入瀨溪流到歷史悠久的弘前城，青森為遊客提供了獨特的旅遊體驗。</p><h2 id="必訪景點" tabindex="-1">必訪景點 <a class="header-anchor" href="#必訪景點" aria-label="Permalink to “必訪景點”">​</a></h2><ul><li><strong><a href="./景點/奧入瀨溪流">奧入瀨溪流</a>：</strong> 日本最美的溪流之一，四季景緻迷人。</li><li><strong><a href="./景點/不老不死溫泉">不老不死溫泉</a>：</strong> 海邊露天溫泉，絕美夕陽景觀。</li><li><strong><a href="./景點/弘前城">弘前城</a>：</strong> 日本第一賞櫻勝地，現存十二天守之一。</li><li><strong><a href="./景點/八甲田山">八甲田山</a>：</strong> 纜車、登山與著名的樹冰奇景。</li><li><strong><a href="./景點/酸湯溫泉">酸湯溫泉</a>：</strong> 擁有千人風呂的古老溫泉。</li><li><strong><a href="./景點/十和田湖">十和田湖</a>：</strong> 橫跨青森與秋田的火山口湖。</li></ul><h2 id="交通資訊" tabindex="-1">交通資訊 <a class="header-anchor" href="#交通資訊" aria-label="Permalink to “交通資訊”">​</a></h2><p>前往青森可以搭乘東北新幹線至新青森站，或是搭乘飛機至青森機場。在縣內觀光，可以利用 JR 鐵路、巴士或租車等交通工具。</p><h2 id="溫馨提示" tabindex="-1">溫馨提示 <a class="header-anchor" href="#溫馨提示" aria-label="Permalink to “溫馨提示”">​</a></h2><ul><li>青森睡魔祭在每年 8 月舉行，是日本最具代表性的祭典之一，建議提前預訂住宿。</li><li><strong>美食推薦：</strong><ul><li><strong>古川市場 (青森魚菜中心)：</strong> 著名的「自選海鮮丼」(のっけ丼)，可以挑選自己喜歡的配料。</li><li><strong>味の札幌 大西：</strong> 青森特色「味噌咖哩牛奶拉麵」的創始店。</li><li><strong>三忠食堂：</strong> 弘前市著名的老字號食堂，以津輕蕎麥麵聞名。</li><li><strong>居酒屋さくら：</strong> 弘前地區受歡迎的在地居酒屋。</li></ul></li><li>青森的蘋果產量位居日本第一，不妨品嚐一下當地的蘋果汁和甜點。</li></ul>',9)])])}const f=r(i,[["render",n]]);export{_ as __pageData,f as default};
